import {useContext} from 'react'
import classNames from 'classnames'
import s from './Sale.module.scss'
import g from '../../../Index.module.scss'
import {Context} from '../../../index'
const ToPay = () => {
    const toggle = () => {
        const discount = document.getElementById("discount") as HTMLBaseElement
        const discountArrow = document.getElementById("discountArrow") as HTMLBaseElement
        discount.classList.toggle(s.show)
        discountArrow.classList.toggle(s.rotate)
    }
    const {cart} = useContext(Context)
    let acum = 0;
    cart.cartItems.forEach(e => acum = e.cart.number * e.item.price + acum );
    return (
        <div className={s.sale}>
            <div className={s.total_priceBox}>
                <div className={s.total_price}>
                    <h2 className={s.titleToPay}>To pay</h2>
                    <div className={s.text}>
                        <p>The value of the products</p>
                        <p>{acum} $</p>
                    </div>
                    <div className={s.text}>
                        <p>Delivery</p>
                        <p>{'0$'}</p>
                    </div>
                    <div className={g.partition}></div>
                    <div className={classNames(s.text, s.boldText)}>
                        <p>To be paid (incl. VAT)</p>
                        <p>{acum} $</p>
                    </div>
                </div>
                <button className={classNames(g.button, s.fullButton)}>buy</button>
            </div>

            <div className={s.discount} id="discount">
                <div className={s.textDiscount}>
                    <p>Add a discount code</p>
                    <p className={s.arrow} id="discountArrow" 
                    onClick={e => toggle()}>〱</p>
                </div>
                <div className={s.enterCode}>
                    <p>Enter Code</p>
                    <input type="text" className={g.input}/>
                </div>
            </div>
        </div>
    )
}

export default ToPay